SELECT

FROM outsource_task t


    t.deleted = 0

        AND (p.project_name LIKE CONCAT('%', #{query.keyword}, '%')
          OR pt.task_name LIKE CONCAT('%', #{query.keyword}, '%')
          OR ac.company_name LIKE CONCAT('%', #{query.keyword}, '%'))


        AND t.project_id = #{query.projectId}


        AND t.agent_company_id = #{query.agentCompanyId}


        AND t.agent_engineer_id = #{query.agentEngineerId}


        AND t.status = #{query.status}


        AND t.deadline IS NOT NULL AND t.deadline < CURDATE()
        AND t.status NOT IN ('CONFIRMED', 'REJECTED', 'OVERDUE')


ORDER BY t.create_time DESC
